const NAME = 'hashRef';

function _directive($state){
    return {
        restrict: 'A',
        scope: false,
        require: false,
        link: function ($scope, iElement, iAttrs){

            const id = iAttrs[NAME];

            iElement.click(function(){

                const options = {
                    reload: true,
                    inherit: false,
                    notify: false
                };
                // 현재 자신의 state 에서 자신의 state 로 이동이 불가 따라서, hash를 비워주고 사용한다.
                $state.transitionTo($state.current, {}, options);

                setTimeout(()=>{
                    $state.transitionTo($state.current, {'#': id}, options);
                });
            });
        }
    };
}

module.exports = {
    directive: {
        name: NAME,
        $inject: ['$state'],
        constructor: _directive
    }
};